import{o as r,c as s,aj as e,ap as l,aq as t,ar as o,as as n,at as p,au as f,av as i,aw as c,ax as d}from"./chunks/framework.C9tMc_wy.js";const g=JSON.parse('{"title":"Механики","description":"","frontmatter":{"title":"Механики","next":false},"headers":[],"relativePath":"mechanics/index.md","filePath":"mechanics/index.md"}'),h={name:"mechanics/index.md"},_=Object.assign(h,{setup(b){return(m,a)=>(r(),s("div",null,[...a[0]||(a[0]=[e('<p><img src="'+l+'" alt="Изображение"></p><h1 id="механики" tabindex="-1">Механики <a class="header-anchor" href="#механики" aria-label="Permalink to “Механики”">​</a></h1><p><span style="color:#8C8C8C;">Информация о работающих модах и механиках на сервере.</span></p><div class="tip custom-block"><p class="custom-block-title"><span style="color:#646CFF;">ПОДСКАЗКА</span></p><p>Играть на сервере можно <strong>без установки каких-либо модов</strong>. Мы поддерживаем их использование для более удобного и интересного взаимодействия между игроками, без какого-либо влияния на игровой процесс.</p><p>Все моды мы собрали в одну коллекцию и опубликовали на <strong>Modrinth</strong>, чтобы вам проще было найти их - <a href="https://modrinth.com/collection/C5RB6gEe" target="_blank" rel="noreferrer">ССЫЛКА</a></p></div><h2 id="балансировка-торговли" tabindex="-1"><span style="color:#c533ffff;">Балансировка торговли</span> <a class="header-anchor" href="#балансировка-торговли" aria-label="Permalink to “Балансировка торговли”">​</a></h2><p>На нашем сервере изменены торги жителей и странствующих торговцев для улучшения экономики.</p><ul><li><a href="https://ru.minecraft.wiki/w/%D0%91%D0%B0%D0%BB%D0%B0%D0%BD%D1%81%D0%B8%D1%80%D0%BE%D0%B2%D0%BA%D0%B0_%D1%82%D0%BE%D1%80%D0%B3%D0%BE%D0%B2%D0%BB%D0%B8" target="_blank" rel="noreferrer">Подробнее</a></li></ul><p><img src="'+t+'" alt="Изображение"></p><h2 id="голосовои-чат" tabindex="-1"><span style="color:#33b4ffff;">Голосовой чат</span> <a class="header-anchor" href="#голосовои-чат" aria-label="Permalink to “Голосовой чат”">​</a></h2><p>На нашем сервере для этого используется мод <span style="color:#33b4ffff;"><strong>Plasmo Voice</strong></span>.</p><ul><li><a href="https://modrinth.com/plugin/plasmo-voice/versions?g=1.21.11&amp;l=fabric&amp;l=forge" target="_blank" rel="noreferrer">Скачать</a></li></ul><h3 id="настроика-и-активация" tabindex="-1"><span style="color:#33b4ffff;">Настройка и активация</span> <a class="header-anchor" href="#настроика-и-активация" aria-label="Permalink to “Настройка и активация”">​</a></h3><p>По умолчанию меню настроек мода открывается по клавише <span style="color:#a8b1ff;"><kbd>V</kbd></span>, а активация микрофона клавишей <span style="color:#a8b1ff;"><kbd>M</kbd></span>. Для лучшей игры рекомендуем во вкладке <strong>Активации</strong> выставить параметр <strong>Дистанция &quot;Локальный&quot;</strong> на <code>32</code> , благодаря чему вы будете дальше слышать игроков.</p><p>Остальное настраивайте на свой вкус.</p><p><img src="'+o+'" alt="Изображение"></p><h2 id="вебкамеры" tabindex="-1"><span style="color:#39e06bff;">Вебкамеры</span> <a class="header-anchor" href="#вебкамеры" aria-label="Permalink to “Вебкамеры”">​</a></h2><p>На нашем сервере для этого используется мод <span style="color:#39e06bff;"><strong>Webcam</strong></span>.</p><ul><li><a href="https://modrinth.com/plugin/webcam-mod/versions?g=1.21.11&amp;l=fabric" target="_blank" rel="noreferrer">Скачать</a></li></ul><h3 id="настроика-и-активация-1" tabindex="-1"><span style="color:#39e06bff;">Настройка и активация</span> <a class="header-anchor" href="#настроика-и-активация-1" aria-label="Permalink to “Настройка и активация”">​</a></h3><p>По умолчанию меню настроек мода открывается по клавише <span style="color:#a8b1ff;"><kbd>C</kbd></span>. Изначально ваша камера отключена и не будет транслироваться на сервер, для включения нужно сперва убедиться в её работоспособности, после чего включить камеру в Minecraft через меню настроек мода.</p><p><img src="'+n+'" alt="Изображение"></p><h2 id="волеибольные-мячи" tabindex="-1"><span style="color:#00d9ffff;">Волейбольные мячи</span> <a class="header-anchor" href="#волеибольные-мячи" aria-label="Permalink to “Волейбольные мячи”">​</a></h2><p>На нашем сервере реализованы полноценные волейбольные мячи, которые можно бросать с разной силой и даже отбивать.</p><p>Чтобы создать волейбольный мяч нужно найти иглобрюха и держа в руке 8 ед. кожи нажать на него, после чего он станет мячом.</p><p>Для броска нужно нажать <span style="color:#a8b1ff;"><kbd>ЛКМ</kbd></span>, а чтобы подорбать нужно рядом с мячом нажать <span style="color:#a8b1ff;"><kbd>Shift</kbd></span>. Сила броска регулируется зажатой клавишей <span style="color:#a8b1ff;"><kbd>Shift</kbd></span>.</p><p>Изменить скин мяча <span style="color:#ffffffff;"><kbd>/ballskin</kbd></span></p><p><img src="'+p+'" alt="Изображение"></p><h2 id="эмоции" tabindex="-1"><span style="color:#ffd900ff;">Эмоции</span> <a class="header-anchor" href="#эмоции" aria-label="Permalink to “Эмоции”">​</a></h2><p>На нашем сервере для этого используется мод <span style="color:#ffd900ff;"><strong>EmoteCraft</strong></span>.</p><ul><li><a href="https://modrinth.com/plugin/emotecraft/versions?g=1.21.11&amp;l=forge&amp;l=fabric" target="_blank" rel="noreferrer">Скачать</a></li></ul><h3 id="настроика-и-активация-2" tabindex="-1"><span style="color:#ffd900ff;">Настройка и активация</span> <a class="header-anchor" href="#настроика-и-активация-2" aria-label="Permalink to “Настройка и активация”">​</a></h3><p>По умолчанию меню с активацией и настроек мода открывается по клавише <span style="color:#a8b1ff;"><kbd>B</kbd></span>. В целом, это всё что нужно знать, но если вдруг Вам необходимо что-то настроить, то открывайте меню, далее <strong>Все эмоции</strong> - <strong>Настройка эмоций</strong> - <strong>Настройка модификаций</strong>.</p><p><img src="'+f+'" alt="Изображение"></p><h2 id="декоративные-блоки" tabindex="-1"><span style="color:#00ffb3ff;">Декоративные блоки</span> <a class="header-anchor" href="#декоративные-блоки" aria-label="Permalink to “Декоративные блоки”">​</a></h2><p>У нас на сервере можно создать блоки для строительства, недоступные в обычном выживании.</p><h3 id="блок-пустоты" tabindex="-1"><span style="color:#a9ffe5ff;">Блок пустоты</span> <a class="header-anchor" href="#блок-пустоты" aria-label="Permalink to “Блок пустоты”">​</a></h3><p>После установки данный блок нельзя добыть, чтобы его убрать нужно на его место поставить любой другой блок.</p><p><img src="'+i+'" alt="Изображение"></p><h3 id="блок-света" tabindex="-1"><span style="color:#a9ffe5ff;">Блок света</span> <a class="header-anchor" href="#блок-света" aria-label="Permalink to “Блок света”">​</a></h3><p>После установки данный блок нельзя добыть, чтобы его убрать нужно на его место поставить любой другой блок.</p><p>Чтобы уменьшить силу света используйте <span style="color:#a8b1ff;"><kbd>Shift + ЛКМ</kbd></span>, а чтобы увеличить <span style="color:#a8b1ff;"><kbd>Shift + ПКМ</kbd></span><em>(только по воздуху)</em>.</p><p><img src="'+c+'" alt="Изображение"></p><h2 id="палочка-отладки" tabindex="-1"><span style="color:#b779ffff;">Палочка отладки</span> <a class="header-anchor" href="#палочка-отладки" aria-label="Permalink to “Палочка отладки”">​</a></h2><p>На нашем сервере вы можете создать <strong>палочку отладки</strong>, которая будет поворачивать блоки и менять их состояние при помощи <span style="color:#a8b1ff;"><kbd>ЛКМ</kbd></span> и <span style="color:#a8b1ff;"><kbd>ПКМ</kbd></span>.</p><p><img src="'+d+'" alt="Изображение"></p>',45)])]))}});export{g as __pageData,_ as default};
